import"./style-C4px4kn2.js";const a="/api/auth",i=document.querySelector("#togglePassword"),r=document.querySelector("#password");i.addEventListener("click",function(){const t=r.getAttribute("type")==="password"?"text":"password";r.setAttribute("type",t),this.classList.toggle("fa-eye"),this.classList.toggle("fa-eye-slash")});document.getElementById("loginForm").addEventListener("submit",async t=>{t.preventDefault();const n=document.getElementById("email").value,o=document.getElementById("password").value;try{const e=await fetch(`${a}/login`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({email:n,password:o})}),s=await e.json();e.ok?(localStorage.setItem("token",s.token),localStorage.setItem("user",JSON.stringify(s.user)),alert("Login successful!"),window.location.href="index.html"):alert(s.message||"Login failed")}catch(e){console.error("Error during login:",e),alert("Something went wrong. Please try again.")}});window.addEventListener("google-login",async t=>{const{credential:n}=t.detail;try{const o=await fetch(`${a}/google-login`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({idToken:n})}),e=await o.json();o.ok?(localStorage.setItem("token",e.token),localStorage.setItem("user",JSON.stringify(e.user)),alert("Google Login successful!"),window.location.href="index.html"):(console.error("Backend Google Login Error:",e),alert("Google Login failed: "+(e.message||"Unknown error")))}catch(o){console.error("Network/Frontend Error during Google login:",o),alert("Google Login failed. Please check if the server is running on port 5000.")}});
